export type TestLocale = {
  title: string;
  description: string;
  estimatedTime: string;
  questions: {
    [id: number]: {
      text: string;
      options: string[];
    };
  };
  results: {
    [key: string]: {
      title: string;
      summary: string;
      description: string;
      strengths: string[];
      caution: string[];
      shareText: string;
    };
  };
};

export type AllTestLocales = {
  [slug: string]: TestLocale;
};

